"""Фоновый запуск серии экспериментов через ExperimentPipeline.run_series."""from __future__ import annotationsfrom typing import Anyfrom PySide6.QtCore import QObject, Signalfrom ...core.pipeline import ExperimentPipelinefrom ...core.types import ExperimentSeriesclass ExperimentWorker(QObject):    finished = Signal(object)   # ExperimentSeries    error = Signal(str)    def __init__(self, pipeline: ExperimentPipeline) -> None:        super().__init__()        self._pipeline = pipeline    def run_series(self,                   signal_name: str, signal_params: dict[str, Any],                   noise_name: str, noise_params: dict[str, Any],                   filter_specs: list,               # list[tuple[str, dict]]                   n_trials: int, seed_mode: str) -> None:        try:            series: ExperimentSeries = self._pipeline.run_series(                signal_name=signal_name, signal_params=signal_params,                noise_name=noise_name, noise_params=noise_params,                filter_specs=list(filter_specs),                n_trials=int(n_trials),                seed_mode=str(seed_mode),            )        except Exception as e:            self.error.emit(f"{type(e).__name__}: {e}")            return        self.finished.emit(series)